mapper.sql:
where r.is_deleted = 0

    and t.program_version_id = #{query.programVersionId}


    and pv.major_id = #{query.majorId}


    and cls.grade_id = #{query.gradeId}


    and t.semester_id = #{query.semesterId}


    and r.model_id = #{query.modelId}


    and t.course_id = #{query.courseId}


    and (
        c.course_name like concat('%', #{query.keyword}, '%')
        or c.course_code like concat('%', #{query.keyword}, '%')
        or obj.objective_name like concat('%', #{query.keyword}, '%')
        or obj.objective_code like concat('%', #{query.keyword}, '%')
        or sem.semester_name like concat('%', #{query.keyword}, '%')
        or cls.class_name like concat('%', #{query.keyword}, '%')
    )

sql.if:
and exists (
    select 1
    from eval_result_detail d
    inner join eval_course_target_result ctr on ctr.id = d.source_id and ctr.is_deleted = 0
    inner join teaching_task t2 on t2.id = ctr.task_id and t2.is_deleted = 0
    inner join org_class cls2 on cls2.id = t2.class_id and cls2.is_deleted = 0
    where d.result_type = 'GRADUATION_REQUIREMENT'
      and d.result_id = r.id
      and d.source_type = 'COURSE_TARGET_RESULT'

        and cls2.grade_id = #{query.gradeId}


        and t2.semester_id = #{query.semesterId}


        and t2.course_id = #{query.courseId}

)

mapper.sql:
where r.is_deleted = 0

    and r.program_version_id = #{query.programVersionId}


    and pv.major_id = #{query.majorId}


    and r.model_id = #{query.modelId}



    and (
        req.requirement_name like concat('%', #{query.keyword}, '%')
        or req.requirement_code like concat('%', #{query.keyword}, '%')
        or maj.major_name like concat('%', #{query.keyword}, '%')
        or pv.version_name like concat('%', #{query.keyword}, '%')
        or pv.version_no like concat('%', #{query.keyword}, '%')
    )

mapper.select:
select ( select count(1) from eval_course_target_result r inner join teaching_task t on t.id = r.task_id and t.is_deleted = 0 left join tr_program_version pv on pv.id = t.program_version_id and pv.is_deleted = 0 left join org_class cls on cls.id = t.class_id and cls.is_deleted = 0 left join edu_semester sem on sem.id = t.semester_id and sem.is_deleted = 0 left join edu_course c on c.id = t.course_id and c.is_deleted = 0 left join edu_course_objective obj on obj.id = r.objective_id and obj.is_deleted = 0
) as courseTargetResultCount, ( select count(1) from eval_graduation_requirement_result r inner join tr_program_version pv on pv.id = r.program_version_id and pv.is_deleted = 0 left join org_major maj on maj.id = pv.major_id and maj.is_deleted = 0 left join tr_graduation_requirement req on req.id = r.requirement_id and req.is_deleted = 0
) as graduationRequirementResultCount, ( select count(1) from eval_graduation_requirement_result r inner join tr_program_version pv on pv.id = r.program_version_id and pv.is_deleted = 0 left join org_major maj on maj.id = pv.major_id and maj.is_deleted = 0 left join tr_graduation_requirement req on req.id = r.requirement_id and req.is_deleted = 0
and r.warning_flag = 1 ) as warningCount, ( select round(coalesce(avg(r.attainment_rate), 0), 2) from eval_course_target_result r inner join teaching_task t on t.id = r.task_id and t.is_deleted = 0 left join tr_program_version pv on pv.id = t.program_version_id and pv.is_deleted = 0 left join org_class cls on cls.id = t.class_id and cls.is_deleted = 0 left join edu_semester sem on sem.id = t.semester_id and sem.is_deleted = 0 left join edu_course c on c.id = t.course_id and c.is_deleted = 0 left join edu_course_objective obj on obj.id = r.objective_id and obj.is_deleted = 0
) as avgCourseTargetAttainmentRate, ( select round(coalesce(avg(r.attainment_rate), 0), 2) from eval_graduation_requirement_result r inner join tr_program_version pv on pv.id = r.program_version_id and pv.is_deleted = 0 left join org_major maj on maj.id = pv.major_id and maj.is_deleted = 0 left join tr_graduation_requirement req on req.id = r.requirement_id and req.is_deleted = 0
) as avgGraduationRequirementAttainmentRate
